"""Pytest suite for string_utils.py.

Covers normal, boundary, and TypeError paths for:
- reverse
- is_palindrome
- count_words
"""

import pytest

from string_utils import count_words, is_palindrome, reverse


# ---------------------------------------------------------------------------
# reverse
# ---------------------------------------------------------------------------


def test_reverse_normal():
    assert reverse("hello") == "olleh"


def test_reverse_unicode():
    assert reverse("héllo 世界") == "界世 olléh"


def test_reverse_empty():
    assert reverse("") == ""


def test_reverse_single_char():
    assert reverse("a") == "a"


def test_reverse_type_error():
    with pytest.raises(TypeError):
        reverse(123)  # type: ignore[arg-type]


def test_reverse_none_type_error():
    with pytest.raises(TypeError):
        reverse(None)  # type: ignore[arg-type]


# ---------------------------------------------------------------------------
# is_palindrome
# ---------------------------------------------------------------------------


def test_is_palindrome_true_basic():
    assert is_palindrome("racecar") is True


def test_is_palindrome_false_basic():
    assert is_palindrome("hello") is False


def test_is_palindrome_ignores_case_and_punctuation():
    assert is_palindrome("A man, a plan, a canal: Panama") is True


def test_is_palindrome_empty_string_is_palindrome():
    assert is_palindrome("") is True


def test_is_palindrome_only_punctuation_is_palindrome():
    # After stripping non-alphanumerics nothing is left, which is a palindrome.
    assert is_palindrome("!!!,,,...") is True


def test_is_palindrome_mixed_alnum():
    assert is_palindrome("12321") is True
    assert is_palindrome("12345") is False


def test_is_palindrome_type_error():
    with pytest.raises(TypeError):
        is_palindrome(["r", "a", "r"])  # type: ignore[arg-type]


# ---------------------------------------------------------------------------
# count_words
# ---------------------------------------------------------------------------


def test_count_words_normal():
    assert count_words("hello world") == 2


def test_count_words_collapses_whitespace():
    assert count_words("  hello   world  \n\tfrom  pytest ") == 4


def test_count_words_empty_string():
    assert count_words("") == 0


def test_count_words_only_whitespace():
    assert count_words("   \t\n  ") == 0


def test_count_words_single_word():
    assert count_words("solo") == 1


def test_count_words_type_error():
    with pytest.raises(TypeError):
        count_words(42)  # type: ignore[arg-type]
